import{_ as i}from"./plugin-vue_export-helper.21dcd24c.js";import{r as a,o as n,c as r,b as t,a as s,w as c,e as d,d as e}from"./app.fa8632a5.js";const l={},h=d('<p>This plugin can automatically append copyright information when visitors copy content from your site, and can also prohibit site copying or selection.</p><h2 id="usage" tabindex="-1"><a class="header-anchor" href="#usage" aria-hidden="true">#</a> Usage</h2><p>This plugin is disabled globally by default, you need to manually enable it by setting <code>copy: true</code> in page frontmatter . Of course, you can set <code>global: true</code> in the plugin options to make it globally enabled, and set <code>copy: false</code> in page frontmatter to disable it.</p><p>To avoid disturbing visitors, copyright information will be appended only when the length of content copied by the user is not less than <code>100</code>. If you want to change this trigger value, please set <code>triggerWords</code>, and this option supports being overrided via <code>copy.triggerWord</code> in page frontmatter.</p><h2 id="disable-copy-and-selection" tabindex="-1"><a class="header-anchor" href="#disable-copy-and-selection" aria-hidden="true">#</a> Disable Copy and Selection</h2><ul><li>If you don&#39;t want users to copy your entire site or specific page text, you can disable copying in plugin options or page frontmatter by setting <code>disableCopy</code>, the latter has higher priority.</li><li>If you don&#39;t want users to select your entire site or specific page text, you can disable selection in plugin options or page frontmatter by setting <code>disableSelection</code>, the latter has higher priority.</li></ul><h2 id="copyright-information" tabindex="-1"><a class="header-anchor" href="#copyright-information" aria-hidden="true">#</a> Copyright Information</h2><p>You can set author and license information via <code>author</code> and <code>license</code> in plugin options. If your site have different authors and license in different pages, you can pass in a function <code>(page: Page) =&gt; string</code> that takes the current page object as parameter and returns the corresponding information.</p><h2 id="customize-copyright-text" tabindex="-1"><a class="header-anchor" href="#customize-copyright-text" aria-hidden="true">#</a> Customize Copyright Text</h2>',9),p=e("You can set copyright information text of the plugin in different languages \u200B\u200Bthrough the "),u=t("code",null,"locales",-1),g=e(" option. For details, see "),f=e("Config \u2192 locales"),y=e(".");function m(b,_){const o=a("RouterLink");return n(),r("div",null,[h,t("p",null,[p,u,g,s(o,{to:"/config.html#locales"},{default:c(()=>[f]),_:1}),y])])}var w=i(l,[["render",m],["__file","guide.html.vue"]]);export{w as default};
